"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[35227],{43039(e,t,i){i.r(t),i.d(t,{assets:()=>d,contentTitle:()=>r,default:()=>l,frontMatter:()=>o,metadata:()=>n,toc:()=>h});let n=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 37 Provisions, Contingent Liabilities and Contingent Assets/deposits-relating-to-taxes-other-tha-f3f38a2b52","title":"Deposits relating to taxes other than income tax (IAS 37)","description":"January 2019","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 37 Provisions, Contingent Liabilities and Contingent Assets/Deposits relating to taxes other than income tax (IAS 37).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 37 Provisions, Contingent Liabilities and Contingent Assets","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-37-provisions-contingent-liabili-b0bcdf04e8/deposits-relating-to-taxes-other-tha-f3f38a2b52","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-37-provisions-contingent-liabili-b0bcdf04e8/deposits-relating-to-taxes-other-tha-f3f38a2b52","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"id":"deposits-relating-to-taxes-other-tha-f3f38a2b52","title":"Deposits relating to taxes other than income tax (IAS 37)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-37-provisions-contingent-liabili-b0bcdf04e8/deposits-relating-to-taxes-other-tha-f3f38a2b52","sidebar_position":1},"sidebar":"knowledgeSidebar","previous":{"title":"Special Purpose Acquisition Companies (SPAC)\uFF1AClassification of Public Shares as Financial Liabilities or Equity (IAS 32)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-32-financial-instruments-present-78e7fb6c7f/special-purpose-acquisition-companie-6bc029a9a5"},"next":{"title":"Negative Low Emission Vehicle Credits (IAS 37)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-37-provisions-contingent-liabili-b0bcdf04e8/negative-low-emission-vehicle-credit-859bc1a3fd"}}');var a=i(74848),s=i(28453);let o={id:"deposits-relating-to-taxes-other-tha-f3f38a2b52",title:"Deposits relating to taxes other than income tax (IAS 37)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-37-provisions-contingent-liabili-b0bcdf04e8/deposits-relating-to-taxes-other-tha-f3f38a2b52",sidebar_position:1},r="Deposits relating to taxes other than income tax (IAS 37)",d={},h=[{value:"Whether the tax deposit gives rise to an asset, a contingent asset or neither",id:"whether-the-tax-deposit-gives-rise-to-an-asset-a-contingent-asset-or-neither",level:2},{value:"Recognising, measuring, presenting and disclosing the tax deposit",id:"recognising-measuring-presenting-and-disclosing-the-tax-deposit",level:2}];function c(e){let t={h1:"h1",h2:"h2",header:"header",p:"p",...(0,s.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"deposits-relating-to-taxes-other-than-income-tax-ias-37",children:"Deposits relating to taxes other than income tax (IAS 37)"})}),"\n",(0,a.jsx)(t.p,{children:"January 2019"}),"\n",(0,a.jsx)(t.p,{children:"The Committee received a request about how to account for deposits relating to taxes that are outside the scope of IAS 12 Income Taxes (ie deposits relating to taxes other than income tax). In the fact pattern described in the request, an entity and a tax authority dispute whether the entity is required to pay the tax. The tax is not an income tax, so it is not within the scope of IAS 12. Any liability or contingent liability to pay the tax is instead within the scope of IAS 37. Taking account of all available evidence, the preparer of the entity\u2019s financial statements judges it probable that the entity will not be required to pay the tax\u2014it is more likely than not that the dispute will be resolved in the entity\u2019s favour. Applying IAS 37, the entity discloses a contingent liability and does not recognise a liability. To avoid possible penalties, the entity has deposited the disputed amount with the tax authority. Upon resolution of the dispute, the tax authority will be required to either refund the tax deposit to the entity (if the dispute is resolved in the entity\u2019s favour) or use the deposit to settle the entity\u2019s liability (if the dispute is resolved in the tax authority\u2019s favour)."}),"\n",(0,a.jsx)(t.h2,{id:"whether-the-tax-deposit-gives-rise-to-an-asset-a-contingent-asset-or-neither",children:"Whether the tax deposit gives rise to an asset, a contingent asset or neither"}),"\n",(0,a.jsx)(t.p,{children:"The Committee observed that if the tax deposit gives rise to an asset, that asset may not be clearly within the scope of any IFRS Standard. Furthermore, the Committee concluded that no IFRS Standard deals with issues similar or related to the issue that arises in assessing whether the right arising from the tax deposit meets the definition of an asset. Accordingly, applying paragraphs 10\u201311 of IAS 8 Accounting Policies, Changes in Accounting Estimates and Errors, the Committee referred to the two definitions of an asset in IFRS literature\u2014the definition in the Conceptual Framework for Financial Reporting issued in March 2018 and the definition in the previous Conceptual Framework that was in place when many existing IFRS Standards were developed. The Committee concluded that the right arising from the tax deposit meets either of those definitions. The tax deposit gives the entity a right to obtain future economic benefits, either by receiving a cash refund or by using the payment to settle the tax liability. The nature of the tax deposit\u2014whether voluntary or required\u2014does not affect this right and therefore does not affect the conclusion that there is an asset. The right is not a contingent asset as defined by IAS 37 because it is an asset, and not a possible asset, of the entity."}),"\n",(0,a.jsx)(t.p,{children:"Consequently, the Committee concluded that in the fact pattern described in the request the entity has an asset when it makes the tax deposit to the tax authority."}),"\n",(0,a.jsx)(t.h2,{id:"recognising-measuring-presenting-and-disclosing-the-tax-deposit",children:"Recognising, measuring, presenting and disclosing the tax deposit"}),"\n",(0,a.jsx)(t.p,{children:"In the absence of a Standard that specifically applies to the asset, an entity applies paragraphs 10\u201311 of IAS 8 in developing and applying an accounting policy for the asset. The entity\u2019s management uses its judgement in developing and applying a policy that results in information that is relevant to the economic decision-making needs of users of financial statements and reliable. The Committee noted that the issues that need to be addressed in developing and applying an accounting policy for the tax deposit may be similar or related to those that arise for the recognition, measurement, presentation and disclosure of monetary assets. If this is the case, the entity\u2019s management would refer to requirements in IFRS Standards dealing with those issues for monetary assets."}),"\n",(0,a.jsx)(t.p,{children:"The Committee concluded that the requirements in IFRS Standards and concepts in the Conceptual Framework for Financial Reporting provide an adequate basis for an entity to account for deposits relating to taxes other than income tax. Consequently, the Committee decided not to add this matter to its standard-setting agenda."})]})}function l(e={}){let{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(c,{...e})}):c(e)}},28453(e,t,i){i.d(t,{R:()=>o,x:()=>r});var n=i(96540);let a={},s=n.createContext(a);function o(e){let t=n.useContext(s);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:o(e.components),n.createElement(s.Provider,{value:t},e.children)}}}]);